//-------------------------------------------------------------------------
// 저장시 호출 되는 함수
//-------------------------------------------------------------------------
scwin.f_Save = async function () {
  // 마감여부 확인 
  if (!(await scwin.f_JobCloseYN())) {
    return;
  }
  if (scwin.checkPlanSave == false) {
    await $c.win.alert($p, "확정으로 조회한 데이타는 계획으로 저장 하실 수 없습니다.");
    return;
  }
  if (ica_FromDate.getValue().trim() != scwin.hid_FromDate.trim() || ed_sacctDeptCd.getValue().trim() != scwin.hid_acctDeptCd.trim() || acb_version.getValue() != scwin.hid_version.trim()) {
    await $c.win.alert($p, "조회 조건인 예산년도, 버전, 부서코드 변경되어서 저장 하실 수 없습니다. 재 조회 및 엑셀파일 Import를 다시 실행하시기 바랍니다.");
    return;
  }

  // 필수입력사항 확인
  let ret = await $c.gus.cfValidate($p, [gr_staffPlan]);
  if (!ret) {
    return;
  }
  for (let i = 0; i < ds_staffPlan.getRowCount(); i++) {
    if (ds_staffPlan.getRowStatus(i) == "C") {
      for (let j = 0; j < i; j++) {
        if (ds_staffPlan.getCellData(i, "occpgrdCd") == ds_staffPlan.getCellData(j, "occpgrdCd")) {
          await $c.win.alert($p, "인원계획등록의 " + (i + 1) + "번째 데이터에서 직급코드은(는) 중복될 수 없습니다.");
          gr_staffPlan.setFocusedCell(i, "occpgrdCd", true);
          return false;
        }
      }
    }
  }

  // 변경된 사항이 있는지 확인.
  if (!ds_staffPlan.getModifiedIndex().length > 0) {
    await $c.win.alert($p, "변경된 사항이 없습니다.");
    return;
  }
  if (acb_version.getDisabled()) {
    await $c.win.alert($p, "해당 년월의 버전정보가 없습니다. 관리실적버전에서 버전을 등록하시기 바랍니다.");
    return;
  }
  let msg = ica_FromDate.getValue().substring(0, 4) + "년 ";
  msg += acb_version.getValue() + "버젼으로 저장하시겠습니까?";
  if (await $c.win.confirm($p, msg)) {
    //ds_staffPlan.UseChangeInfo="true";
    sbm_saveStaffPlan.action = "/ac.co.bizplan.SaveStaffPlanCMD.do";
    await $c.sbm.execute($p, sbm_saveStaffPlan);
  }
};

