scwin.f_Apply = async function () {
  let countCheck = 0;
  for (let i = 0; i < ds_staffPlan.getRowCount(); i++) {
    if (ds_staffPlan.getCellData(i, "num") == "T" || ds_staffPlan.getCellData(i, "num") == 1) {
      for (let j = parseInt(ds_staffPlan.getCellData(i, "month")) + 5; j < 18; j++) {
        let targetColId = gr_staffPlan.getColumnID(j);
        ds_staffPlan.setCellData(i, targetColId, ds_staffPlan.getCellData(i, gr_staffPlan.getColumnID(parseInt(ds_staffPlan.getCellData(i, "month")) + 5)));
      }
      //          f_ReSum(i); // 합계를 재계산한다.
      countCheck++;
    }
  }
  if (countCheck <= 0) {
    await $c.win.alert($p, "일괄적용을 하고자 하는 Row를 체크 하시기 바랍니다.");
  }
};

//-------------------------------------------------------------------------
// 마감체크
//-------------------------------------------------------------------------
scwin.f_JobCloseYN = async function () {
  scwin.f_setWrkNoFromDate();
  //cfJobCloseYN(마감요청구분,마감년월,마감일,작업번호,관리번호,리턴구분);
  let isClose = await udc_closeYn.cfJobCloseYN("CUR", scwin.fromDate, "00", scwin.wrkNo, "0", "ARR", "", ed_coCd.getValue());

  // 선행마감 작업에 대한 검사
  if (isClose[3] == "PRE") {
    if (isClose[0] == "1") {
      $c.win.alert($p, "선행작업 " + isClose[2] + "이 미마감되어서 현재 작업을 진행할 수 없습니다.");
      return false;
    } else if (isClose[0] == "0") {
      $c.win.alert($p, "선행작업 " + isClose[2] + "이 마감작업중이어서 현재 작업을 진행할 수 없습니다.");
      return false;
    }
  }

  // 해당마감 작업에 대한 검사
  if (isClose[3] == "CUR") {
    if (isClose[0] == "0") {
      $c.win.alert($p, isClose[2] + "(이)가 마감중입니다.");
      return false;
    } else if (isClose[0] == "2") {
      $c.win.alert($p, isClose[2] + "(이)가 마감완료가 되었습니다");
      return false;
    } else {
      return true;
    }
  }
  return true; // 기본값
};

//-------------------------------------------------------------------------
// 조회 및 마감확인시 작업코드 날짜 세팅하는 함수
//-------------------------------------------------------------------------
scwin.f_setWrkNoFromDate = function () {
  scwin.wrkNo = ACConstants.CLOSE_PLAN_CREATION;
  scwin.fromDate = ica_FromDate.getValue().trim() + "00";
};

//------------------------------------------- 
// 그리드 높이 늘리고 줄이기 
//------------------------------------------- 
scwin.f_grdHeiht = function (gridObj, size) {
  let strHeight = gridObj.getStyle("height");
  let intHeight = parseInt(strHeight.replace("px", ""));
  intHeight = intHeight + size;
  if (intHeight > 0) {
    gridObj.setStyle("height", intHeight + "px");
  }
};

//-------------------------------------------------------------------------
// 자회사 회계 시스템 추가에 따른 설정 
//-------------------------------------------------------------------------
scwin.f_setCompanyInfo = function () {
  // 사용자 구분이 자회사('SA')가 아닌 경우, 소속회사를  '동부 EXPRESS'로  Default set
  if (scwin.vUserHomeClsCd != ACConstants.SUBSIDIARY_USER_HOME_CLS_CD) {
    scwin.vLoginCoCd = ACConstants.CO_CD_DONGBU;
    scwin.vLoginCoClsCd = ACConstants.CO_CLS_CD_DONGBU;
  }
  scwin.isStart = true;
  ed_coCd.setValue(scwin.vLoginCoCd);
  scwin.f_PopUpCompanyInfo('T');
};

//-------------------------------------------------------------------------
// 회사 입력 팝업 
//-------------------------------------------------------------------------
scwin.f_PopUpCompanyInfo = async function (pWinCloseTF) {
  await udc_dongbuGroupCompanyInfo.cfCommonPopUp(scwin.udc_dongbuGroupCompanyInfo_callBackFunc, ed_coCd.getValue(), "", pWinCloseTF, null, null, null, null, null, null, null, null, null);
};
scwin.udc_dongbuGroupCompanyInfo_callBackFunc = function (rtnList) {
  // SET	
  if (rtnList != null) {
    if (rtnList[0] == "N/A") return;
    ed_coCd.setValue(rtnList[0]); // 코드
    ed_coNm.setValue(rtnList[5]); // 회사명 
    scwin.txtCoClsCd = rtnList[1]; // 회사구분
  } else {
    ed_coCd.setValue("");
    ed_coNm.setValue("");
    scwin.txtCoClsCd = "";
  }
  if (scwin.isStart == true) {
    if (scwin.txtCoClsCd > ACConstants.CO_CLS_CD_DONGBU) {
      scwin.isSubCompany = true;
    } else {
      scwin.isSubCompany = false;
    }
    if ('T' == scwin.privAdmin || !scwin.isSubCompany) {
      // ADMIN 권한이 있는 경우, 동부 EXPRESS 인 경우 
      $c.gus.cfEnableObjects($p, [ed_coCd, ed_coNm, btn_company]);
    } else {
      $c.gus.cfDisableObjects($p, [ed_coCd, ed_coNm, btn_company]);
    }
  }
  scwin.isStart = false;
};
scwin.sbm_retrieveVer_submitdone = function (e) {
  scwin.f_SetFinalVer();
};
scwin.sbm_searchStaffPlan_submitdone = async function (e) {
  // 조회 조건이 계획으로 조회 했을경우 저장 가능으로 변경함.
  if (acb_planDcsn.getValue() == "1") {
    scwin.checkPlanSave = true;
  } else {
    scwin.checkPlanSave = false;
  }

  // 조회된 건수를 Grid 왼쪽 하단에 표시한다.
  let rowCnt = ds_staffPlan.getRowCount();
  totalRows.setValue(rowCnt);
  gr_staffPlan.setFocusedCell(0, 0);
  if (rowCnt == 0) {
    await $c.win.alert($p, MSG_CM_ERR_003);
  }
};
scwin.sbm_saveStaffPlan_submitdone = async function (e) {
  if (e.responseJSON.resultDataSet[0].Code != -1) {
    await $c.win.alert($p, MSG_CM_INF_001);
    scwin.f_Retrieve();
  }
};
scwin.gr_staffPlan_oncellclick = function (rowIndex, columnIndex, colId) {
  if (colId == "occpgrdCd" && ds_staffPlan.getRowStatus(rowIndex) == "C") {
    gr_staffPlan.setColumnReadOnly("occpgrdCd", false);
  } else {
    gr_staffPlan.setColumnReadOnly("occpgrdCd", true);
  }
};
scwin.gr_staffPlan_ontextimageclick = function (rowIndex, columnIndex) {
  let gacctDeptCd = "";
  let gacctDeptNm = "";
  scwin.f_openPopUp(gacctDeptCd, gacctDeptNm, '2', 'SKIP');
};
scwin.udc_acctDeptCdInfo5_onblurCodeEvent = function (e) {
  scwin.f_CheckPopUp(ed_sacctDeptCd, ed_sacctDeptNm, '1', 'CD');
};
scwin.udc_acctDeptCdInfo5_onblurNameEvent = function (e) {
  scwin.f_CheckPopUp(ed_sacctDeptCd, ed_sacctDeptNm, '1', 'NM');
};
scwin.udc_dongbuGroupCompanyInfo_onblurCodeEvent = function (e) {
  if (ed_coCd.getValue() != "") {
    scwin.f_PopUpCompanyInfo('T');
  } else {
    ed_coNm.setValue("");
  }
};
scwin.udc_dongbuGroupCompanyInfo_onclickEvent = function (e) {
  scwin.f_PopUpCompanyInfo('F');
};
scwin.ica_FromDate_onchange = function () {
  scwin.f_LoadVer();
};
scwin.udc_acctDeptCdInfo5_onclickEvent = function (e) {
  scwin.f_openPopUp(ed_sacctDeptCd, ed_sacctDeptNm, '1', 'ALL');
};
scwin.btn_init_onclick = function (e) {
  $c.gus.cfInitObjects($p, table1, [ica_FromDate, ed_sacctDeptCd, ed_sacctDeptNm, acb_version, ed_coCd, ed_coNm]);
};
scwin.sbm_cd_submitdone = function (e) {
  let coList = ds_cd.getColData("cdDesc");
  let isMatch = coList.includes(scwin.memJson.userId);
  if (isMatch) {
    btn_confirm.setStyle("display", "block");
  } else {
    btn_confirm.setStyle("display", "none");
  }
};
scwin.gr_staffPlan_onviewchange = async function (info) {
  if (info.colId == "occpgrdCd") {
    if (ds_staffPlan.getCellData(info.rowIndex, "occpgrdCd").trim() == "") {
      ds_staffPlan.setCellData(info.rowIndex, "occpgrdCd", "");
      ds_staffPlan.setCellData(info.rowIndex, "occpgrdNm", "");
      return;
    }
    let gacctDeptCd = info.newValue;
    let gacctDeptNm = ds_staffPlan.getCellData(info.rowIndex, "occpgrdNm");
    await udc_occpgrdCdInfo.cfCommonPopUp(scwin.udc_occpgrdCdInfo_callBackFunc, gacctDeptCd, gacctDeptNm, "T", null, null, null, null, "2,3,,,", "450", "500", null, "T");
  }
};
scwin.gr_excel_onfilereadend = function (value) {
  ds_staffPlan.removeAll();
  scwin.f_Import();
};
